CREATE OR REPLACE FUNCTION public.add_admin_by_email(p_email text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id UUID;
BEGIN
  -- 检查调用者是否是管理员
  IF NOT EXISTS (SELECT 1 FROM admins WHERE user_id = auth.uid()) THEN
    RAISE EXCEPTION '没有权限执行此操作';
  END IF;
  
  -- 查找用户ID
  SELECT id INTO v_user_id
  FROM auth.users
  WHERE email ILIKE p_email;
  
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION '未找到该邮箱对应的用户';
  END IF;
  
  -- 检查用户是否已经是管理员
  IF EXISTS (SELECT 1 FROM admins WHERE user_id = v_user_id) THEN
    RAISE EXCEPTION '该用户已经是管理员';
  END IF;
  
  -- 添加管理员
  INSERT INTO admins (user_id)
  VALUES (v_user_id);
  
  RETURN TRUE;
END;
$function$

CREATE OR REPLACE FUNCTION public.add_comment(p_post_id uuid, p_user_id uuid, p_content text, p_parent_id uuid)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_comment_id UUID;
BEGIN
  INSERT INTO comments (post_id, user_id, content, parent_id)
  VALUES (p_post_id, p_user_id, p_content, p_parent_id)
  RETURNING id INTO v_comment_id;
  UPDATE posts SET comments_count = comments_count + 1 WHERE id = p_post_id;
  RETURN v_comment_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.delete_post(p_post_id uuid, p_user_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_is_admin BOOLEAN;
  v_post_exists BOOLEAN;
  v_is_author BOOLEAN;
BEGIN
  -- 检查用户是否是管理员
  SELECT EXISTS (
    SELECT 1 FROM admin_users WHERE user_id = p_user_id
  ) INTO v_is_admin;
  
  -- 记录操作日志
  INSERT INTO operation_logs (
    operation_type,
    user_id,
    target_id,
    is_admin_operation,
    details
  ) VALUES (
    'delete_post',
    p_user_id,
    p_post_id,
    v_is_admin,
    jsonb_build_object('post_id', p_post_id, 'user_id', p_user_id, 'is_admin', v_is_admin)
  );
  
  -- 检查帖子是否存在
  SELECT EXISTS (
    SELECT 1 FROM posts WHERE id = p_post_id
  ) INTO v_post_exists;
  
  IF NOT v_post_exists THEN
    RAISE EXCEPTION '帖子不存在';
  END IF;
  
  -- 检查用户是否是帖子作者
  SELECT EXISTS (
    SELECT 1 FROM posts WHERE id = p_post_id AND user_id = p_user_id
  ) INTO v_is_author;
  
  -- 检查用户是否是帖子作者或管理员
  IF v_is_admin OR v_is_author THEN
    -- 删除帖子相关的评论
    DELETE FROM comments WHERE post_id = p_post_id;
    
    -- 删除帖子相关的点赞
    DELETE FROM likes WHERE post_id = p_post_id;
    
    -- 删除帖子
    DELETE FROM posts WHERE id = p_post_id;
  ELSE
    RAISE EXCEPTION '没有权限删除此帖子';
  END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.delete_post_admin(p_post_id uuid, p_user_id uuid, p_is_admin boolean)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_post_exists BOOLEAN;
  v_is_author BOOLEAN;
  v_is_admin BOOLEAN;
BEGIN
  -- 检查帖子是否存在
  SELECT EXISTS(SELECT 1 FROM posts WHERE id = p_post_id) INTO v_post_exists;
  
  IF NOT v_post_exists THEN
    RAISE EXCEPTION '帖子不存在';
  END IF;
  
  -- 检查用户是否是帖子作者
  SELECT user_id = p_user_id FROM posts WHERE id = p_post_id INTO v_is_author;
  
  -- 如果声称是管理员，验证管理员身份
  IF p_is_admin THEN
    SELECT EXISTS(SELECT 1 FROM admins WHERE user_id = p_user_id) INTO v_is_admin;
  ELSE
    v_is_admin := FALSE;
  END IF;
  
  -- 只有作者或管理员可以删除帖子
  IF NOT (v_is_author OR v_is_admin) THEN
    RAISE EXCEPTION '没有权限删除此帖子';
  END IF;
  
  -- 删除帖子相关的点赞
  DELETE FROM likes WHERE post_id = p_post_id;
  
  -- 删除帖子相关的评论
  DELETE FROM comments WHERE post_id = p_post_id;
  
  -- 删除帖子
  DELETE FROM posts WHERE id = p_post_id;
  
  RETURN TRUE;
END;
$function$

CREATE OR REPLACE FUNCTION public.unlike_post(p_post_id uuid, p_user_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  DELETE FROM likes WHERE post_id = p_post_id AND user_id = p_user_id;
  UPDATE posts SET likes_count = GREATEST(likes_count - 1, 0) WHERE id = p_post_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.update_modified_column()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.update_updated_at_column()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$function$
